import tensorflow as tf
from tensorflow import keras
from sklearn.model_selection import train_test_split
from sklearn.preprocessing import ImageDataGenerator
from tensorflow.keras import layers
from flask import Flask, request, jsonify
import pandas as pd
import numpy as np
import os
from PIL import Image
from io import BytesIO

app = Flask(__name__)

# API endpoint for user upload
@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        file.save(os.path.join(app.config['UPLOAD_FOLDER'], filename))
        # Load CSV data from uploaded file
        df = pd.read_csv(filename, header=None)
        X_train, X_test, y_train, y_test = train_test_split(df.iloc[:, 1:], df[0], test_size=0.2, random_state=42)
        
        # Data augmentation for training
        datagen = ImageDataGenerator(rescale=1./255,
                                      shear_range=0.2,
                                      zoom_range=0.2,
                                      horizontal_flip=True)
        train_generator = datagen.flow(X_train.values.astype('float32').reshape(-1, 28, 28, 1), y_train, batch_size=64)
        
        # Model definition
        model = keras.Sequential([
            layers.Conv2D(32, (3, 3), activation='relu', input_shape=(28, 28, 1)),
            layers.MaxPooling2D((2, 2)),
            layers.Flatten(),
            layers.Dense(64, activation='relu'),
            layers.Dropout(0.2),
            layers.Dense(10)
        ])
        
        # Compile the model
        model.compile(optimizer='adam',
                      loss=tf.keras.losses.SparseCategoricalCrossentropy(from_logits=True),
                      metrics=['accuracy'])
        
        # Train the model
        history = model.fit(train_generator, epochs=5)
        
        return jsonify({'message': 'Model trained successfully'}), 200
    else:
        return jsonify({'error': 'File not allowed'}), 400

if __name__ == '__main__':
    app.run(debug=True)

# Model serving endpoint
@app.route('/predict', methods=['POST'])
def predict():
    data = request.get_json()
    img_data = BytesIO(data['image'])
    img = Image.open(img_data)
    img = tf.keras.preprocessing.image.img_to_array(img)
    predictions = model.predict(tf.expand_dims(img, axis=0))
    return jsonify({'predictions': np.argmax(predictions[0])}), 200

if __name__ == '__main__':
    app.run(debug=True)

# Contributing endpoint
@app.route('/contribute', methods=['POST'])
def contribute():
    data = request.get_json()
    new_example = {'feature1': data['feature1'], 'feature2': data['feature2'], 'label': data['label']}
    X_train.append(new_example)
    y_train.append(data['label'])
    # Save updated CSV
    df = pd.DataFrame({'feature1': [example[0] for example in X_train], 
                       'feature2': [example[1] for example in X_train],
                       'label': y_train})
    df.to_csv('data.csv', index=False)
    
    return jsonify({'message': 'Contributed data saved successfully'}), 200

if __name__ == '__main__':
    app.run(debug=True)